content:
rflow: hidden;
}

.filter-btn {
  background: var(--bg-input);
  border: none;
  padding: 5px 12px;
  font-family: var(--font-ui);
  font-size: 11px;
  font-weight: 600;
  color: var(--text-muted);
  cursor: pointer;
  transition: all var(--transition);
}

.filter-btn.active {
  background: var(--gold-medium);
  color: var(--gold-bright);
}

.search-input {
  flex: 1;
  background: var(--bg-input);
  border: 1px solid var(--border);
  border-radius: var(--radius-xs);
  padding: 5px 10px;
  font-family: var(--font-ui);
  font-size: 12px;
  color: var(--text-primary);
  outline: none;
}

.search-input:focus {
  border-color: var(--gold);
}

.auto-scroll-btn {
  background: var(--bg-input);
  border: 1px solid var(--border);
  border-radius: var(--radius-xs);
  padding: 4px 8px;
  cursor: pointer;
  color: var(--text-muted);
  font-size: 12px;
}

.auto-scroll-btn.active {
  background: var(--gold-medium);
  color: var(--gold-bright);
}

.log-output {
  flex: 1;
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-top: none;
  border-radius: 0 0 var(--radius-md) var(--radius-md);
  padding: 12px 16px;
  overflow-y: auto;
  font-family: var(--font-mono);
  font-size: 11.5px;
  line-height: 1.9;
  min-height: 300px;
  max-height: 60vh;
}

.log-line {
  padding: 1px 8px;
  border-radius: 3px;
  transition: background var(--transition);
}

.log-line:hover {
  background: var(--bg-card-hover);
}

.log-warn {
  border-left: 3px solid var(--amber);
  background: var(--amber-soft);
}

.log-error {
  border-left: 3px solid var(--coral);
  background: var(--coral-soft);
}

.log-ts {
  color: var(--text-dim);
  opacity: 0.6;
  margin-right: 6px;
}

.log-level {
  font-weight: 600;
  margin-right: 6px;
}

.log-msg {
  color: var(--text-primary);
}
